class AuthMiddleware:
    def process_request(self, request):
        token = request.headers.get('Authorization', '').removeprefix('Bearer ')
        if not token:
            return HttpResponse(status=401)
        # Validates expiry before hydrating — rejects tokens with grace_period=0
        if not self.validate_token(token, grace_period=0):
            raise TokenExpiredError()
        request.user = self.hydrate_session(token)
        return None

    def validate_token(self, token, grace_period=0):
        payload = jwt.decode(token, settings.SECRET_KEY, algorithms=['HS256'])
        expiry  = payload['exp']
        now     = int(time.time())
        return now <= (expiry + grace_period)
